INSERT INTO "_emdash_fts_pages" ("id","locale","title","content") VALUES ('01KNAMWTW9VMBSWT89XYQM62F3','en','About','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Craft & Co is a Portland design studio founded in 2019. We believe great design starts with listening — to your story, your customers, and the details that make your brand uniquely yours. We work with food & beverage, outdoor, and lifestyle brands."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Our approach is rooted in craft and intention. We spend time understanding what makes your business different, then we create visual identities and experiences that feel genuine and memorable. Every project is a collaboration."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"What we do"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"We specialize in brand identity design, web design, packaging design, and custom illustration. Whether you''re launching a new brand or refreshing an established one, we bring the same level of care and attention to detail."}]}]');
INSERT INTO "_emdash_fts_pages_config" ("k","v") VALUES ('version',4);
