INSERT INTO "_emdash_fts_projects" ("id","locale","title","summary","content") VALUES ('01KNAMWTWJWN3B9SA8SZGS1ZZC','en','Timber Brewing Co','Complete brand identity and packaging design for a craft brewery focused on sustainability and heritage.','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Timber Brewing Co is a new craft brewery in Portland committed to using local ingredients and sustainable practices. They needed a visual identity that reflected their values while standing out in a crowded market."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"The identity"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"We created a wordmark inspired by timber grain and brewing tradition, paired with a warm, earthy color palette. The mark works at any scale and translates beautifully to their can and bottle designs."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"Packaging"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"The packaging extends the identity with custom illustrations that reference the brewery''s sourcing practices. Each beer style has a unique illustration, making the collection feel cohesive yet distinct."}]}]');
INSERT INTO "_emdash_fts_projects" ("id","locale","title","summary","content") VALUES ('01KNAMWTWVZZ2HHREYTW9WKSAS','en','Fern & Moss','E-commerce website design for an online plant shop specializing in rare and unusual houseplants.','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Fern & Moss is an online plant shop built on the belief that unusual plants deserve equally unusual homes. They needed an e-commerce website that felt like browsing a curated collection rather than shopping a catalog."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"Design approach"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"We designed the site to showcase each plant as a character. Large photography, minimal text, and an organic layout create an immersive browsing experience. The color palette shifts subtly based on plant type, creating natural categories without cluttering the interface."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"Features"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Custom care guides for each plant, a plant identification tool, and a community forum where collectors share photos of their plants. The site has increased engagement and repeat purchases."}]}]');
INSERT INTO "_emdash_fts_projects" ("id","locale","title","summary","content") VALUES ('01KNAMWTX1Z06SG557P7STKCRF','en','Mountain Journal','Editorial design for a quarterly outdoor magazine celebrating mountain culture and environmental storytelling.','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Mountain Journal is a quarterly publication dedicated to mountain culture, environmental conservation, and the people who live in and care for mountain communities."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"The design system"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"We developed a flexible design system that uses bold typography, generous white space, and a restrained color palette. Each issue explores a new region, and the design adapts while maintaining a consistent visual language."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"Layout philosophy"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"We prioritize the photography and editorial content, using a modular grid that adapts to different story types. Pull quotes and callouts are treated as design elements, breaking up the rhythm of longer features."}]}]');
INSERT INTO "_emdash_fts_projects" ("id","locale","title","summary","content") VALUES ('01KNAMWTX8RF6YXAX6Q713AWSX','en','Nomad Coffee','Complete rebrand for a specialty coffee roaster expanding from their Portland roastery to national distribution.','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Nomad Coffee started as a local roastery but quickly gained a following for their single-origin beans and commitment to direct trade. They needed a rebrand that could scale nationally while maintaining their craft authenticity."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"The mark"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"We created a simplified wordmark that feels both timeless and contemporary. The accompanying badge system allows flexibility for different product lines and collaborations."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"Packaging and collateral"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Custom bag designs feature origin maps and tasting notes, turning each product into a storytelling opportunity. A refined color palette and consistent typography create a premium feel that supports their direct trade positioning."}]}]');
INSERT INTO "_emdash_fts_projects" ("id","locale","title","summary","content") VALUES ('01KNAMWTXAFRZTDJPDN03Y38AJ','en','Pacific Trails','Wayfinding and signage system design for a 40,000-acre state park spanning three distinct ecosystems.','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Pacific Trails State Park encompasses forests, wetlands, and coastal bluffs. The park needed a comprehensive wayfinding system that could guide visitors across diverse landscapes while respecting the natural environment."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"System design"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"We developed a modular signage system using natural materials and minimal visual hierarchy. Each zone uses distinct colors derived from the landscape, helping visitors understand which ecosystem they''re in."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"Implementation"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Custom trail maps, marker designs, and interpretive signage create a cohesive experience that encourages exploration while providing clear navigation. The system uses locally-sourced cedar and weather-resistant finishes for durability and sustainability."}]}]');
INSERT INTO "_emdash_fts_projects_config" ("k","v") VALUES ('version',4);
