INSERT INTO "ec_pages" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","content") VALUES ('01KNAMWTW9VMBSWT89XYQM62F3','about','published',NULL,NULL,'2026-04-03T21:44:55.947Z','2026-04-03T21:44:55.947Z','2026-04-03T21:44:55.945Z',NULL,NULL,1,NULL,NULL,'en','01KNAMWTW9VMBSWT89XYQM62F3','About','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Craft & Co is a Portland design studio founded in 2019. We believe great design starts with listening — to your story, your customers, and the details that make your brand uniquely yours. We work with food & beverage, outdoor, and lifestyle brands."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Our approach is rooted in craft and intention. We spend time understanding what makes your business different, then we create visual identities and experiences that feel genuine and memorable. Every project is a collaboration."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"What we do"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"We specialize in brand identity design, web design, packaging design, and custom illustration. Whether you''re launching a new brand or refreshing an established one, we bring the same level of care and attention to detail."}]}]');
INSERT INTO "ec_projects" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","featured_image","client","year","summary","content","gallery","url") VALUES ('01KNAMWTWJWN3B9SA8SZGS1ZZC','timber-brewing-co','published',NULL,NULL,'2026-04-03T21:44:55.954Z','2026-04-03T21:44:55.954Z','2026-04-03T21:44:55.954Z',NULL,NULL,1,NULL,NULL,'en','01KNAMWTWJWN3B9SA8SZGS1ZZC','Timber Brewing Co','https://images.unsplash.com/photo-1558642452-9d2a7deb7f62?w=1200&h=900&fit=crop','Timber Brewing Co','2024','Complete brand identity and packaging design for a craft brewery focused on sustainability and heritage.','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Timber Brewing Co is a new craft brewery in Portland committed to using local ingredients and sustainable practices. They needed a visual identity that reflected their values while standing out in a crowded market."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"The identity"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"We created a wordmark inspired by timber grain and brewing tradition, paired with a warm, earthy color palette. The mark works at any scale and translates beautifully to their can and bottle designs."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"Packaging"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"The packaging extends the identity with custom illustrations that reference the brewery''s sourcing practices. Each beer style has a unique illustration, making the collection feel cohesive yet distinct."}]}]',NULL,'https://timberbrewing.example.com');
INSERT INTO "ec_projects" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","featured_image","client","year","summary","content","gallery","url") VALUES ('01KNAMWTWVZZ2HHREYTW9WKSAS','fern-and-moss','published',NULL,NULL,'2026-04-03T21:44:55.963Z','2026-04-03T21:44:55.963Z','2026-04-03T21:44:55.963Z',NULL,NULL,1,NULL,NULL,'en','01KNAMWTWVZZ2HHREYTW9WKSAS','Fern & Moss','https://images.unsplash.com/photo-1459411552884-841db9b3cc2a?w=1200&h=900&fit=crop','Fern & Moss','2024','E-commerce website design for an online plant shop specializing in rare and unusual houseplants.','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Fern & Moss is an online plant shop built on the belief that unusual plants deserve equally unusual homes. They needed an e-commerce website that felt like browsing a curated collection rather than shopping a catalog."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"Design approach"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"We designed the site to showcase each plant as a character. Large photography, minimal text, and an organic layout create an immersive browsing experience. The color palette shifts subtly based on plant type, creating natural categories without cluttering the interface."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"Features"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Custom care guides for each plant, a plant identification tool, and a community forum where collectors share photos of their plants. The site has increased engagement and repeat purchases."}]}]',NULL,'https://fernandmoss.example.com');
INSERT INTO "ec_projects" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","featured_image","client","year","summary","content","gallery","url") VALUES ('01KNAMWTX1Z06SG557P7STKCRF','mountain-journal','published',NULL,NULL,'2026-04-03T21:44:55.969Z','2026-04-03T21:44:55.969Z','2026-04-03T21:44:55.969Z',NULL,NULL,1,NULL,NULL,'en','01KNAMWTX1Z06SG557P7STKCRF','Mountain Journal','https://images.unsplash.com/photo-1506880018603-83d5b814b5a6?w=1200&h=900&fit=crop','Mountain Journal','2023','Editorial design for a quarterly outdoor magazine celebrating mountain culture and environmental storytelling.','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Mountain Journal is a quarterly publication dedicated to mountain culture, environmental conservation, and the people who live in and care for mountain communities."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"The design system"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"We developed a flexible design system that uses bold typography, generous white space, and a restrained color palette. Each issue explores a new region, and the design adapts while maintaining a consistent visual language."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"Layout philosophy"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"We prioritize the photography and editorial content, using a modular grid that adapts to different story types. Pull quotes and callouts are treated as design elements, breaking up the rhythm of longer features."}]}]',NULL,NULL);
INSERT INTO "ec_projects" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","featured_image","client","year","summary","content","gallery","url") VALUES ('01KNAMWTX8RF6YXAX6Q713AWSX','nomad-coffee','published',NULL,NULL,'2026-04-03T21:44:55.976Z','2026-04-03T21:44:55.976Z','2026-04-03T21:44:55.976Z',NULL,NULL,1,NULL,NULL,'en','01KNAMWTX8RF6YXAX6Q713AWSX','Nomad Coffee','https://images.unsplash.com/photo-1447933601403-0c6688de566e?w=1200&h=900&fit=crop','Nomad Coffee','2023','Complete rebrand for a specialty coffee roaster expanding from their Portland roastery to national distribution.','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Nomad Coffee started as a local roastery but quickly gained a following for their single-origin beans and commitment to direct trade. They needed a rebrand that could scale nationally while maintaining their craft authenticity."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"The mark"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"We created a simplified wordmark that feels both timeless and contemporary. The accompanying badge system allows flexibility for different product lines and collaborations."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"Packaging and collateral"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Custom bag designs feature origin maps and tasting notes, turning each product into a storytelling opportunity. A refined color palette and consistent typography create a premium feel that supports their direct trade positioning."}]}]',NULL,'https://nomadcoffee.example.com');
INSERT INTO "ec_projects" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","featured_image","client","year","summary","content","gallery","url") VALUES ('01KNAMWTXAFRZTDJPDN03Y38AJ','pacific-trails','published',NULL,NULL,'2026-04-03T21:44:55.979Z','2026-04-03T21:44:55.979Z','2026-04-03T21:44:55.978Z',NULL,NULL,1,NULL,NULL,'en','01KNAMWTXAFRZTDJPDN03Y38AJ','Pacific Trails','https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=1200&h=900&fit=crop','Pacific Trails State Park','2023','Wayfinding and signage system design for a 40,000-acre state park spanning three distinct ecosystems.','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Pacific Trails State Park encompasses forests, wetlands, and coastal bluffs. The park needed a comprehensive wayfinding system that could guide visitors across diverse landscapes while respecting the natural environment."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"System design"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"We developed a modular signage system using natural materials and minimal visual hierarchy. Each zone uses distinct colors derived from the landscape, helping visitors understand which ecosystem they''re in."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"Implementation"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Custom trail maps, marker designs, and interpretive signage create a cohesive experience that encourages exploration while providing clear navigation. The system uses locally-sourced cedar and weather-resistant finishes for durability and sustainability."}]}]',NULL,NULL);
